import React, { useEffect, useState } from "react";
// 1. IMPORT YOUR NEW COMPONENTS
import { CategoryFilter } from "../components/CategoryFilter";
import { FavoriteWrapper } from "../components/FavoriteWrapper";
import { Link } from "react-router-dom";
import styles from "../style/Home.module.css";
import MovieCard from "../components/MovieCard";
import {
  getPopularMovies,
  getTopRatedMovies,
  hasApiKey,
  imageUrl,
} from "../api/tmdb";

function Home() {
  const [popularMovies, setPopularMovies] = useState([]);
  const [topRatedMovies, setTopRatedMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [activeFilter, setActiveFilter] = useState("All");

  useEffect(() => {
    if (!hasApiKey) {
      setLoading(false);
      setError("Add your TMDB API key in .env as REACT_APP_TMDB_API_KEY");
      return;
    }

    async function loadHomeMovies() {
      try {
        const [popular, topRated] = await Promise.all([
          getPopularMovies(),
          getTopRatedMovies(),
        ]);
        setPopularMovies(popular);
        setTopRatedMovies(topRated);
      } catch (err) {
        setError("Could not load movies. Please check your API key.");
      } finally {
        setLoading(false);
      }
    }
    loadHomeMovies();
  }, []);

  const heroMovie = popularMovies[0];
  const screenImages = topRatedMovies.slice(0, 5);
  const topMovies = topRatedMovies.slice(4, 8);

  // 2. LOGIC FOR FILTERING
  const getFilteredMovies = () => {
    let filtered = [...popularMovies];
    if (activeFilter === "Top Rated (8+)") {
      filtered = filtered.filter((m) => m.vote_average >= 8);
    } else if (activeFilter === "Good (7+)") {
      filtered = filtered.filter(
        (m) => m.vote_average >= 7 && m.vote_average < 8,
      );
    }
    return filtered.slice(0, 10);
  };

  const trendingMovies = getFilteredMovies();

  return (
    <main className={styles.home}>
      {loading && <p className={styles.message}>Loading movies...</p>}
      {error && <p className={styles.message}>{error}</p>}

      {!loading && !error && heroMovie && (
        <>
          <section
            className={styles.hero}
            style={{
              backgroundImage: `linear-gradient(90deg, rgba(31, 16, 19, 0.92), rgba(31, 16, 19, 0.45)), url(${imageUrl(heroMovie.backdrop_path, "original")})`,
            }}
          >
            <div className={styles.heroContent}>
              <span className={styles.badge}>Popular Now</span>
              <h1>{heroMovie.title}</h1>
              <p>{heroMovie.overview}</p>
              <div className={styles.heroActions}>
                <Link to={`/movie/${heroMovie.id}`}>View Details</Link>
              </div>
            </div>
          </section>

          <section className={styles.section}>
            <div className={styles.sectionHeader}>
              <div>
                <h2>Trending Now</h2>
                <span>Movies Trending</span>
              </div>

              {/* 3. IMPLEMENT CATEGORY FILTER */}
              <CategoryFilter
                categories={[
                  { id: "All", name: "All" },
                  { id: "Top Rated (8+)", name: "Top Rated (8+)" },
                  { id: "Good (7+)", name: "Good (7+)" },
                ]}
                activeCategory={activeFilter}
                onSelectCategory={setActiveFilter}
              />
            </div>

            <div className={styles.moviesGrid}>
              {trendingMovies.map((movie) => (
                // 4. WRAP THE MOVIE CARD
                <FavoriteWrapper key={movie.id} movie={movie}>
                  <MovieCard movie={movie} />
                </FavoriteWrapper>
              ))}
            </div>
          </section>

          {/* ... rest of your code (About Section, Top Rated, etc) ... */}
        </>
      )}
    </main>
  );
}

export default Home;
